+  });
+
+  it('should still record suppressed notifications in the list', async () => {
+    preferencesService.updatePreferences('alice@example.com', {
+      email: { enabled: false },
+    });
+
+    await notificationService.sendNotification({
+      type: 'order-confirmation',
+      channel: 'email',
+      recipient: 'alice@example.com',
+      subject: 'Test',
+      body: 'Test body',
+      priority: 'normal',
+    });
+
+    expect(notificationService.getNotificationCount()).toBe(1);
+    expect(notificationService.getNotificationsForRecipient('alice@example.com')).toHaveLength(1);
+  });
+});

