/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications.
 * Currently supports email channel settings; designed to
 * accommodate additional channels in future.
 */

import type { NotificationType } from './notification.js';

/**
 * How frequently email notifications are delivered.
 * - immediate: sent as soon as the event occurs
 * - daily-digest: batched and sent once per day
 * - weekly-digest: batched and sent once per week
 *
 * Note: Only 'immediate' is currently implemented.
 * Digest modes are defined for future use.
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest';

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  /** Whether email notifications are enabled at all */
  enabled: boolean;
  /** Delivery frequency */
  frequency: EmailFrequency;
  /** Notification categories the user is subscribed to */
  subscribedCategories: NotificationType[];
}

/**
 * Full user notification preferences record.
 */
export interface UserPreferences {
  /** Matches the user's ID */
  id: string;
  /** The user this preferences record belongs to */
  userId: string;
  /** Email notification settings */
  email: EmailPreferences;
  /** When the preferences were created */
  createdAt: Date;
  /** When the preferences were last updated */
  updatedAt: Date;
}

/**
 * Input for updating notification preferences.
 * All fields are optional — only provided fields are changed.
 */
export interface UpdatePreferencesInput {
  email?: Partial<EmailPreferences>;
}

/**
 * All notification categories available for subscription.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order-confirmation',
  'order-status-update',
  'welcome',
  'account-updated',
];

/**
 * Default email preferences for new users.
 * All notifications enabled, immediate delivery, subscribed to all categories.
 */
export function getDefaultEmailPreferences(): EmailPreferences {
  return {
    enabled: true,
    frequency: 'immediate',
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  };
}

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 * Depends on the Database utility layer for storage.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import type { EmailFrequency } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as EmailFrequency,
        subscribedCategories: JSON.parse(record['emailSubscribedCategories'] as string) as NotificationType[],
      },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailSubscribedCategories: JSON.stringify(entity.email.subscribedCategories),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences for a specific user.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — business logic for user notification preferences.
 *
 * Manages CRUD operations on preferences and provides a check method
 * that the NotificationService uses to decide whether to send a notification.
 *
 * Depends on:
 * - PreferencesRepository (data layer) for persistence
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserPreferences,
  UpdatePreferencesInput,
} from '../models/user-preferences.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';
import { getDefaultEmailPreferences } from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: PreferencesRepository) {}

  /**
   * Get preferences for a user. If none exist, creates default preferences.
   */
  getOrCreatePreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    this.logger.info(`Creating default preferences for user ${userId}`);
    const now = new Date();
    const preferences: UserPreferences = {
      id: generatePreferencesId(),
      userId,
      email: getDefaultEmailPreferences(),
      createdAt: now,
      updatedAt: now,
    };

    return this.preferencesRepository.save(preferences);
  }

  /**
   * Update a user's notification preferences.
   * Merges the provided input with existing preferences.
   */
  updatePreferences(userId: string, input: UpdatePreferencesInput): UserPreferences {
    const current = this.getOrCreatePreferences(userId);

    const updatedEmail = input.email
      ? {
          enabled: input.email.enabled ?? current.email.enabled,
          frequency: input.email.frequency ?? current.email.frequency,
          subscribedCategories:
            input.email.subscribedCategories ?? current.email.subscribedCategories,
        }
      : current.email;

    const updated: UserPreferences = {
      ...current,
      email: updatedEmail,
      updatedAt: new Date(),
    };

    this.logger.info(`Updating preferences for user ${userId}`);
    return this.preferencesRepository.update(current.id, updated);
  }

  /**
   * Check whether a notification should be sent to a user
   * based on their preferences.
   *
   * Returns true if the notification should proceed, false if suppressed.
   */
  shouldSendNotification(
    userId: string,
    channel: NotificationChannel,
    type: NotificationType,
  ): boolean {
    const prefs = this.preferencesRepository.findByUserId(userId);

    // No preferences stored = use defaults (send everything)
    if (!prefs) {
      return true;
    }

    if (channel === 'email') {
      if (!prefs.email.enabled) {
        this.logger.info(`Email notifications disabled for user ${userId}, suppressing ${type}`);
        return false;
      }
      if (!prefs.email.subscribedCategories.includes(type)) {
        this.logger.info(`User ${userId} not subscribed to ${type}, suppressing`);
        return false;
      }
      return true;
    }

    // For channels without preference support yet, allow by default
    return true;
  }
}

