import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { ALL_NOTIFICATION_CATEGORIES } from '../../src/models/user-preferences.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { NotificationType } from '../../src/models/notification.js';

describe('PreferencesService', () => {
  let db: Database;
  let repository: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repository = new PreferencesRepository(db);
    service = new PreferencesService(repository);
    resetPreferencesIdCounter();
  });

  describe('getOrCreatePreferences', () => {
    it('should create default preferences for a new user', () => {
      const prefs = service.getOrCreatePreferences('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.id).toBe('pref-0001');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should return existing preferences without creating duplicates', () => {
      const first = service.getOrCreatePreferences('user-1');
      const second = service.getOrCreatePreferences('user-1');

      expect(first.id).toBe(second.id);
      expect(repository.count()).toBe(1);
    });

    it('should create separate preferences for different users', () => {
      const prefs1 = service.getOrCreatePreferences('user-1');
      const prefs2 = service.getOrCreatePreferences('user-2');

      expect(prefs1.userId).toBe('user-1');
      expect(prefs2.userId).toBe('user-2');
      expect(prefs1.id).not.toBe(prefs2.id);
      expect(repository.count()).toBe(2);
    });
  });

  describe('updatePreferences', () => {
    it('should disable email notifications', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
      // Other fields remain unchanged
      expect(updated.email.frequency).toBe('immediate');
      expect(updated.email.subscribedCategories).toEqual(ALL_NOTIFICATION_CATEGORIES);
    });

    it('should change email frequency', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updatePreferences('user-1', {
        email: { frequency: 'daily-digest' },
      });

      expect(updated.email.frequency).toBe('daily-digest');
      expect(updated.email.enabled).toBe(true);
    });

    it('should update subscribed categories', () => {
      service.getOrCreatePreferences('user-1');
      const updated = service.updatePreferences('user-1', {
        email: { subscribedCategories: ['order-confirmation'] },
      });

      expect(updated.email.subscribedCategories).toEqual(['order-confirmation']);
    });

    it('should create preferences if none exist when updating', () => {
      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
      });

      expect(updated.userId).toBe('user-1');
      expect(updated.email.enabled).toBe(false);
    });

    it('should persist updates across reads', () => {
      service.updatePreferences('user-1', {
        email: { frequency: 'weekly-digest', subscribedCategories: ['welcome'] },
      });

      const prefs = service.getOrCreatePreferences('user-1');
      expect(prefs.email.frequency).toBe('weekly-digest');
      expect(prefs.email.subscribedCategories).toEqual(['welcome']);
    });
  });

  describe('shouldSendNotification', () => {
    it('should allow notifications when no preferences are stored', () => {
      const result = service.shouldSendNotification('user-1', 'email', 'order-confirmation');
      expect(result).toBe(true);
    });

    it('should allow notifications with default preferences', () => {
      service.getOrCreatePreferences('user-1');
      const result = service.shouldSendNotification('user-1', 'email', 'order-confirmation');
      expect(result).toBe(true);
    });

    it('should suppress notifications when email is disabled', () => {
      service.updatePreferences('user-1', { email: { enabled: false } });
      const result = service.shouldSendNotification('user-1', 'email', 'order-confirmation');
      expect(result).toBe(false);
    });

    it('should suppress notifications for unsubscribed categories', () => {
      service.updatePreferences('user-1', {
        email: { subscribedCategories: ['order-confirmation'] },
      });

      expect(service.shouldSendNotification('user-1', 'email', 'order-confirmation')).toBe(true);
      expect(service.shouldSendNotification('user-1', 'email', 'order-status-update')).toBe(false);
      expect(service.shouldSendNotification('user-1', 'email', 'welcome')).toBe(false);
    });

    it('should allow non-email channels by default', () => {
      service.updatePreferences('user-1', { email: { enabled: false } });
      // Even with email disabled, other channels should pass
      const result = service.shouldSendNotification('user-1', 'webhook', 'order-confirmation');
      expect(result).toBe(true);
    });

    it('should check all notification types correctly', () => {
      service.updatePreferences('user-1', {
        email: { subscribedCategories: ['order-confirmation', 'account-updated'] },
      });

      const types: NotificationType[] = [
        'order-confirmation',
        'order-status-update',
        'welcome',
        'account-updated',
      ];
      const results = types.map((t) => service.shouldSendNotification('user-1', 'email', t));
      expect(results).toEqual([true, false, false, true]);
    });
  });
});

describe('NotificationService with preferences', () => {
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;
  let db: Database;

  beforeEach(() => {
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    db = new Database();
    const repository = new PreferencesRepository(db);
    preferencesService = new PreferencesService(repository);
    notificationService.setPreferencesService(preferencesService);
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
  });

  it('should suppress email when user has disabled email notifications', async () => {
    preferencesService.updatePreferences('alice@example.com', {
      email: { enabled: false },
    });

    const notification = await notificationService.sendNotification({
      type: 'order-confirmation',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Test',
      body: 'Test body',
      priority: 'normal',
    });

    expect(notification.delivered).toBe(false);
    expect(notification.error).toBe('Suppressed by user preferences');
  });

  it('should suppress email for unsubscribed category', async () => {
    preferencesService.updatePreferences('alice@example.com', {
      email: { subscribedCategories: ['welcome'] },
    });

    const notification = await notificationService.sendNotification({
      type: 'order-confirmation',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Test',
      body: 'Test body',
      priority: 'normal',
    });

    expect(notification.delivered).toBe(false);
    expect(notification.error).toBe('Suppressed by user preferences');
  });

  it('should allow email when user preferences permit it', async () => {
    preferencesService.getOrCreatePreferences('alice@example.com');

    const notification = await notificationService.sendNotification({
      type: 'order-confirmation',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Test',
      body: 'Test body',
      priority: 'normal',
    });

    // No adapter registered, so delivered=false but NOT due to preferences
    expect(notification.error).not.toBe('Suppressed by user preferences');
  });

  it('should allow notifications when no preferences service is set', async () => {
    const plainService = new NotificationService(eventBus);
    // No setPreferencesService called

    const notification = await plainService.sendNotification({
      type: 'order-confirmation',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Test',
      body: 'Test body',
      priority: 'normal',
    });

    // Should proceed (fail for no adapter, not for preferences)
    expect(notification.error).not.toBe('Suppressed by user preferences');
  });

  it('should still record suppressed notifications in the list', async () => {
    preferencesService.updatePreferences('alice@example.com', {
      email: { enabled: false },
    });

    await notificationService.sendNotification({
      type: 'order-confirmation',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Test',
      body: 'Test body',
      priority: 'normal',
    });

    expect(notificationService.getNotificationCount()).toBe(1);
    expect(notificationService.getNotificationsForRecipient('alice@example.com')).toHaveLength(1);
  });
});
